arguments.file_text:
@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services

<div class="profile-section">
    <h4>Profile Settings</h4>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview">
                <label class="form-label">Avatar</label>
                <div class="avatar-image-container">
                    @if (!string.IsNullOrWhiteSpace(AvatarUrl))
                    {
                        <img src="@AvatarUrl" alt="Avatar" class="avatar-image" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <small class="text-muted text-break">@AvatarUrl</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@IsSaving">
            Discard Changes
        </button>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !HasUserEdited)
        {
            LoadFromProfile(Profile);
        }
    }

    private bool HasUserEdited;

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
        HasUserEdited = false;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        HasUserEdited = false;
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        ShowSuccess = false;
        StateHasChanged();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.profile-section {
    max-width: 800px;
}

.avatar-preview {
    text-align: center;
}

.avatar-image-container {
    width: 120px;
    height: 120px;
    margin: 0.5rem auto 0.75rem;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
    color: #adb5bd;
}

@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services

<div class="notifications-section">
    <h4>Notification Preferences</h4>
    <p class="text-muted">Control how you receive notifications</p>
    <hr />

    <div class="mb-4">
        <h6>Notification Channels</h6>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">
                📧 Email Notifications
                <small class="d-block text-muted">Receive notifications via email</small>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">
                📱 Push Notifications
                <small class="d-block text-muted">Receive push notifications on your devices</small>
            </label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">
                📰 Weekly Digest
                <small class="d-block text-muted">Get a weekly summary of activity</small>
            </label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        <p class="text-muted small">Select channels to mute</p>

        @foreach (var channel in AvailableChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3" role="alert">
            ✅ Notification preferences saved!
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];

    private bool IsSaving;
    private bool ShowSuccess;

    private static readonly string[] AvailableChannels =
        ["General", "Announcements", "Engineering", "Design", "Marketing", "Support"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.notifications-section {
    max-width: 600px;
}

@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services

<div class="security-section">
    <h4>Security Settings</h4>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @* Change Password Panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <span>🔑 Change Password</span>
            <span>@(PasswordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (PasswordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label">Current Password</label>
                    <input type="password" class="form-control" @bind="CurrentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">New Password</label>
                    <input type="password" class="form-control" @bind="NewPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="ConfirmPassword" />
                </div>

                @if (!string.IsNullOrEmpty(PasswordError))
                {
                    <div class="alert alert-danger py-2">@PasswordError</div>
                }
                @if (PasswordSuccess)
                {
                    <div class="alert alert-success py-2">✅ Password updated successfully!</div>
                }

                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@IsChangingPassword">
                    @if (IsChangingPassword)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Update Password
                </button>
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">🛡️ Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (TwoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                            <span>Your account is protected with 2FA</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark me-1">Disabled</span>
                            <span>Enable 2FA for additional security</span>
                        }
                    </small>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="TwoFactorEnabled" />
                </div>
            </div>
            @if (Settings?.LastPasswordChange is not null)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    @* Active Sessions Table *@
    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">💻 Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            @if (Sessions.Count == 0)
            {
                <p class="text-muted p-3">No active sessions found.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != Sessions[0])
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    @* Revoke Confirmation Dialog *@
    @if (SessionToRevoke is not null)
    {
        <div class="modal-backdrop fade show"></div>
        <div class="modal d-block fade show" tabindex="-1">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> in <strong>@SessionToRevoke.Location</strong>?</p>
                        <p class="text-muted small">This will sign out the device immediately.</p>
                    </div>
                    <div class="modal-footer">
                        <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button type="button" class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                            @if (IsRevoking)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Revoke Session
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool PasswordPanelOpen;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? PasswordError;
    private bool PasswordSuccess;
    private bool IsChangingPassword;

    private bool TwoFactorEnabled;
    private List<ActiveSession> Sessions = [];

    private ActiveSession? SessionToRevoke;
    private bool IsRevoking;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            Sessions = [.. Settings.Sessions];
        }
    }

    private async Task ChangePasswordAsync()
    {
        PasswordError = null;
        PasswordSuccess = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            PasswordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(NewPassword) || NewPassword.Length < 8)
        {
            PasswordError = "New password must be at least 8 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            PasswordError = "Passwords do not match.";
            return;
        }

        IsChangingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            PasswordSuccess = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            PasswordError = ex.Message;
        }
        finally
        {
            IsChangingPassword = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        SessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        SessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (SessionToRevoke is null) return;
        IsRevoking = true;
        try
        {
            await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
            Sessions.RemoveAll(s => s.Id == SessionToRevoke.Id);
            SessionToRevoke = null;
        }
        finally
        {
            IsRevoking = false;
        }
    }
}

.security-section {
    max-width: 800px;
}

@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services

<div class="appearance-section">
    <h4>Appearance Settings</h4>
    <p class="text-muted">Customize how the application looks</p>
    <hr />

    <div class="row">
        <div class="col-md-6">
            @* Theme Selector *@
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">
                            @GetThemeIcon(theme) @theme
                        </label>
                    </div>
                }
            </div>

            @* Font Size Selector *@
            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            @* Language Dropdown *@
            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="Language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">
                        Compact Mode
                        <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                    </label>
                </div>
