@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services

<div class="appearance-section">
    <h4>Appearance Settings</h4>
    <p class="text-muted">Customize how the application looks</p>
    <hr />

    <div class="row">
        <div class="col-md-6">
            @* Theme Selector *@
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(Theme == theme)"
                               @onchange="() => Theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">
                            @GetThemeIcon(theme) @theme
                        </label>
                    </div>
                }
            </div>

            @* Font Size Selector *@
            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(FontSize == size)"
                               @onchange="() => FontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            @* Language Dropdown *@
            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="Language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">
                        Compact Mode
                        <small class="d-block text-muted">Reduce spacing and padding throughout the UI</small>
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3" role="alert">
                    ✅ Appearance settings saved!
                </div>
            }
        </div>

        @* Live Preview *@
        <div class="col-md-6">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewThemeClass()" style="@GetPreviewFontStyle()">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body @(CompactMode ? "compact" : "")">
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <div class="preview-card">
                        <span class="preview-card-title">Card Title</span>
                        <span class="preview-card-text">Card content preview</span>
                    </div>
                    <button class="preview-button">Sample Button</button>
                </div>
                <div class="preview-footer">
                    <small>Theme: @Theme · Font: @FontSize · @(CompactMode ? "Compact" : "Normal")</small>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "en";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private static string GetThemeIcon(string theme) => theme switch
    {
        "Light" => "☀️",
        "Dark" => "🌙",
        "System" => "💻",
        _ => ""
    };

    private string GetPreviewThemeClass() => Theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewFontStyle() => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.appearance-section {
    max-width: 900px;
}

.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid rgba(128, 128, 128, 0.2);
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark .preview-header {
    background: #181825;
}

.preview-body {
    padding: 1rem;
}

.preview-body.compact {
    padding: 0.5rem 0.75rem;
}

.preview-body.compact .preview-text {
    margin-bottom: 0.25rem;
}

.preview-body.compact .preview-card {
    padding: 0.4rem 0.6rem;
    margin-bottom: 0.4rem;
}

.preview-text {
    margin-bottom: 0.75rem;
}

.preview-card {
    border: 1px solid rgba(128, 128, 128, 0.2);
    border-radius: 0.375rem;
    padding: 0.75rem;
    margin-bottom: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.preview-light .preview-card {
    background: #f8f9fa;
}

.preview-dark .preview-card {
    background: #313244;
}

.preview-card-title {
    font-weight: 600;
}

.preview-card-text {
    opacity: 0.7;
}

.preview-button {
    border: none;
    border-radius: 0.375rem;
    padding: 0.35rem 1rem;
    font-size: inherit;
    cursor: default;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

.preview-dark .preview-button {
    background: #89b4fa;
    color: #1e1e2e;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid rgba(128, 128, 128, 0.2);
    opacity: 0.6;
}

