arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Components.Settings
@using sv_9b6e6ef77bfa4dac9ac01de663dafb74.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@ActiveSection" OnSectionChanged="SetActiveSection" />

    <div class="settings-content">
        @if (IsLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "Profile":
                    <ProfileSection Profile="@Profile" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@NotificationPrefs" OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="@Security"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@Appearance" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string ActiveSection = "Profile";
    private bool IsLoading = true;

    private UserProfile? Profile;
    private NotificationPrefs? NotificationPrefs;
    private SecuritySettings? Security;
    private AppearanceSettings? Appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadCurrentSectionAsync();
    }

    private async Task SetActiveSection(string section)
    {
        ActiveSection = section;
        IsLoading = true;
        await LoadCurrentSectionAsync();
    }

    private async Task LoadCurrentSectionAsync()
    {
        switch (ActiveSection)
        {
            case "Profile" when Profile is null:
                Profile = await SettingsService.GetProfileAsync();
                break;
            case "Notifications" when NotificationPrefs is null:
                NotificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                break;
            case "Security" when Security is null:
                Security = await SettingsService.GetSecuritySettingsAsync();
                break;
            case "Appearance" when Appearance is null:
                Appearance = await SettingsService.GetAppearanceAsync();
                break;
        }
        IsLoading = false;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        Profile = profile;
    }

